import { useEffect, useState } from "react";
import api from "../api";

export default function YouthList() {
  const [youth, setYouth] = useState([]);
  const [searchPhone, setSearchPhone] = useState("");

  // Admin key prompt (optional)
  useEffect(() => {
    let adminKey = localStorage.getItem("adminKey");
    if (!adminKey) {
      adminKey = prompt("Enter admin secret key:");
      if (adminKey) localStorage.setItem("adminKey", adminKey);
    }
    fetchYouth();
  }, []);

  const fetchYouth = async () => {
    try {
      const res = await api.get("/");
      setYouth(res.data);
    } catch (err) {
      console.error(err.response?.data || err.message);
      alert("Admin access required");
    }
  };

  const checkIn = async (id) => {
    try {
      await api.patch(`/${id}/checkin`);
      fetchYouth();
      alert("Checked in successfully");
    } catch {
      alert("Check-in failed");
    }
  };

  const deleteYouth = async (id) => {
    if (!window.confirm("Delete this youth?")) return;
    try {
      await api.delete(`/${id}`);
      fetchYouth();
      alert("Deleted successfully");
    } catch {
      alert("Delete failed");
    }
  };

  const searchByPhone = async () => {
    if (!searchPhone) return fetchYouth();
    try {
      const res = await api.get(`/search/${searchPhone}`);
      setYouth(res.data);
    } catch {
      alert("Search failed");
    }
  };

  return (
    <div>
      <h2>Youth List (Admin)</h2>
      <div>
        <input
          placeholder="Search by phone"
          value={searchPhone}
          onChange={(e) => setSearchPhone(e.target.value)}
        />
        <button onClick={searchByPhone}>Search</button>
        <button
          onClick={() => {
            setSearchPhone("");
            fetchYouth();
          }}
        >
          Reset
        </button>
      </div>
      {youth.length === 0 ? (
        <p>No youth found.</p>
      ) : (
        youth.map((y) => (
          <div key={y._id}>
            <strong>{y.fullName}</strong> - {y.congregation}
            {!y.checkedIn ? (
              <button onClick={() => checkIn(y._id)}>Check In</button>
            ) : (
              <span style={{ color: "green" }}>Checked In</span>
            )}
            <button style={{ color: "red" }} onClick={() => deleteYouth(y._id)}>
              Delete
            </button>
          </div>
        ))
      )}
    </div>
  );
}
